class Solution:
    def powerfulIntegers(self, x: int, y: int, bound: int) -> List[int]:
        res = set()
        for i in range(int(math.log2(bound)) + 1):
            for j in range(int(math.log2(bound)) + 1):
                if x ** i + y ** j <= bound:
                    res.add(x ** i + y ** j)
        return list(res)
